@import '../../utils/focus-ring.css';

:host {
  display: inline-flex;
  flex: 0 0 auto;
  width: var(--dimension-size-400);
  height: var(--dimension-size-400);
  min-width: var(--dimension-size-400);
  min-height: var(--dimension-size-400);
  outline: none;
  --ds-button-filled-bg: var(--color-background-bold-brand);
  --ds-button-filled-fg: var(--color-foreground-faint-brand);
}

.button-filled {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  padding: var(--dimension-space-075);
  border: none;
  border-radius: var(--dimension-radius-025);
  background-color: var(--ds-button-filled-bg);
  color: var(--ds-button-filled-fg);
  cursor: pointer;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
  position: relative;
  overflow: hidden;
  transition:
    background-color var(--effect-motion-short-2),
    color var(--effect-motion-short-2),
    transform var(--effect-motion-short-2);
}

.button-filled::before,
.button-filled::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background: transparent;
  pointer-events: none;
  transition: none;
}

.button-filled::before {
  z-index: 1;
}

.button-filled::after {
  z-index: 2;
}

.button-filled:hover:not(.button-filled--inactive)::before {
  background: color-mix(in oklch, var(--ds-button-filled-bg) 85%, var(--ds-button-filled-fg));
}

.button-filled:active:not(.button-filled--inactive) {
  transform: scale(var(--dimension-scale-subtle));
}

.button-filled:active:not(.button-filled--inactive)::before {
  background: color-mix(in oklch, var(--ds-button-filled-bg) 80%, var(--ds-button-filled-fg));
}

.button-filled--inactive {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

.button-filled__icon-wrap {
  position: relative;
  width: var(--dimension-iconography-md);
  height: var(--dimension-iconography-md);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  z-index: 2;
}

/* ── Intent + contrast (bold default) ─────────────────────────────────────── */

.button-filled--intent-neutral {
